import React, { useState, useEffect } from 'react';
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
  Link,
  useNavigate
} from 'react-router-dom';
import {
  ThemeProvider,
  createTheme,
  CssBaseline,
  AppBar,
  Toolbar,
  Typography,
  Button,
  Box,
  Card,
  CardContent,
  TextField,
  IconButton,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  CircularProgress,
  Alert,
  Grid,
  LinearProgress,
  Chip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Paper,
  Container,
  Avatar,
  Divider,
  CardActions,
  Fab,
  Tooltip,
  Stack,
  useMediaQuery,
  Fade,
  Grow,
  Zoom,
  Badge,
  Menu,
  MenuItem,
  InputAdornment,
  ToggleButton,
  ToggleButtonGroup,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TablePagination,
  Rating,
  SpeedDial,
  SpeedDialAction,
  SpeedDialIcon,
  Snackbar,
  AlertTitle
} from '@mui/material';
import { alpha } from '@mui/material/styles';
import {
  Menu as MenuIcon,
  Dashboard as DashboardIcon,
  Upload as UploadIcon,
  Assessment as AssessmentIcon,
  Work as WorkIcon,
  History as HistoryIcon,
  Logout as LogoutIcon,
  Analytics as AnalyticsIcon,
  CheckCircle as CheckCircleIcon,
  Error as ErrorIcon,
  TrendingUp as TrendingUpIcon,
  Description as DescriptionIcon,
  CloudUpload as CloudUploadIcon,
  Home as HomeIcon,
  Login as LoginIcon,
  AppRegistration as AppRegistrationIcon,
  School as SchoolIcon,
  Business as BusinessIcon,
  Code as CodeIcon,
  Rocket as RocketIcon,
  Speed as SpeedIcon,
  Security as SecurityIcon,
  Delete as DeleteIcon,
  Visibility as VisibilityIcon,
  Edit as EditIcon,
  Download as DownloadIcon,
  Refresh as RefreshIcon,
  Star as StarIcon,
  StarBorder as StarBorderIcon,
  TrendingDown as TrendingDownIcon,
  InsertDriveFile as InsertDriveFileIcon,
  PictureAsPdf as PictureAsPdfIcon,
  Article as ArticleIcon,
  Person as PersonIcon,
  Search as SearchIcon,
  FilterList as FilterListIcon,
  MoreVert as MoreVertIcon,
  Share as ShareIcon,
  Bookmark as BookmarkIcon,
  BookmarkBorder as BookmarkBorderIcon,
  Timeline as TimelineIcon,
  BarChart as BarChartIcon,
  Close as CloseIcon,
  Check as CheckIcon,
  Add as AddIcon,
  Email as EmailIcon,
  Phone as PhoneIcon,
  LocationOn as LocationOnIcon,
  LinkedIn as LinkedInIcon,
  GitHub as GitHubIcon,
  Twitter as TwitterIcon,
  Language as LanguageIcon,
  Info as InfoIcon,
  Warning as WarningIcon,
  AutoAwesome as AutoAwesomeIcon,
  Psychology as PsychologyIcon,
  Calculate as CalculateIcon,
  ThumbUp as ThumbUpIcon,
  ThumbDown as ThumbDownIcon,
  Apps as AppsIcon,
  FormatListBulleted as FormatListBulletedIcon,
  TrendingUp as TrendingUp,
  Speed as SpeedIconNew,
  Assessment
} from '@mui/icons-material';
import { DropzoneArea } from 'mui-file-dropzone';
import { LineChart, Line, BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, Legend, ResponsiveContainer } from 'recharts';
import axios from 'axios';

// ==================== PINK THEME ====================

const theme = createTheme({
  palette: {
    mode: 'light',
    primary: {
      main: '#ff69b4',
      light: '#ff9acb',
      dark: '#ff1493',
      gradient: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)'
    },
    secondary: {
      main: '#ff6b6b',
      light: '#ff8787',
      dark: '#fa5252'
    },
    success: {
      main: '#51cf66',
      light: '#69db7e',
      dark: '#37b24d'
    },
    warning: {
      main: '#ff922b',
      light: '#ffa94d',
      dark: '#f76707'
    },
    error: {
      main: '#ff6b6b',
      light: '#ff8787',
      dark: '#fa5252'
    },
    info: {
      main: '#ff69b4',
      light: '#ff9acb',
      dark: '#ff1493'
    },
    background: {
      default: '#fff5f8',
      paper: '#ffffff',
      gradient: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)'
    },
    text: {
      primary: '#4a4a4a',
      secondary: '#8a8a8a'
    }
  },
  typography: {
    fontFamily: '"Inter", "Poppins", "Roboto", "Helvetica", "Arial", sans-serif',
    h1: { fontWeight: 800, fontSize: '3.5rem', letterSpacing: '-0.02em' },
    h2: { fontWeight: 700, fontSize: '2.5rem', letterSpacing: '-0.01em' },
    h3: { fontWeight: 600, fontSize: '2rem' },
    h4: { fontWeight: 600, fontSize: '1.5rem' },
    h5: { fontWeight: 600, fontSize: '1.25rem' },
    h6: { fontWeight: 600, fontSize: '1rem' },
    body1: { fontSize: '1rem', lineHeight: 1.5 },
    body2: { fontSize: '0.875rem', lineHeight: 1.5 },
  },
  shape: {
    borderRadius: 16,
  },
  shadows: [
    'none',
    '0px 2px 4px rgba(0,0,0,0.05)',
    '0px 4px 8px rgba(0,0,0,0.05)',
    '0px 8px 16px rgba(0,0,0,0.05)',
    '0px 12px 24px rgba(0,0,0,0.05)',
    '0px 16px 32px rgba(0,0,0,0.05)',
    '0px 20px 40px rgba(0,0,0,0.05)',
    '0px 24px 48px rgba(0,0,0,0.05)',
    '0px 28px 56px rgba(0,0,0,0.05)',
    '0px 32px 64px rgba(0,0,0,0.05)',
    '0px 36px 72px rgba(0,0,0,0.05)',
    '0px 40px 80px rgba(0,0,0,0.05)',
    '0px 44px 88px rgba(0,0,0,0.05)',
    '0px 48px 96px rgba(0,0,0,0.05)',
    '0px 52px 104px rgba(0,0,0,0.05)',
    '0px 56px 112px rgba(0,0,0,0.05)',
    '0px 60px 120px rgba(0,0,0,0.05)',
    '0px 64px 128px rgba(0,0,0,0.05)',
    '0px 68px 136px rgba(0,0,0,0.05)',
    '0px 72px 144px rgba(0,0,0,0.05)',
    '0px 76px 152px rgba(0,0,0,0.05)',
    '0px 80px 160px rgba(0,0,0,0.05)',
  ],
  components: {
    MuiButton: {
      styleOverrides: {
        root: {
          textTransform: 'none',
          fontWeight: 600,
          borderRadius: 12,
          padding: '8px 20px',
        },
        contained: {
          boxShadow: 'none',
          '&:hover': {
            boxShadow: '0px 4px 12px rgba(255, 105, 180, 0.3)',
          },
        },
      },
    },
    MuiCard: {
      styleOverrides: {
        root: {
          borderRadius: 20,
          boxShadow: '0px 4px 20px rgba(0, 0, 0, 0.05)',
          transition: 'all 0.3s ease',
          '&:hover': {
            transform: 'translateY(-4px)',
            boxShadow: '0px 12px 40px rgba(0, 0, 0, 0.1)',
          },
        },
      },
    },
    MuiPaper: {
      styleOverrides: {
        root: {
          borderRadius: 20,
        },
      },
    },
    MuiChip: {
      styleOverrides: {
        root: {
          borderRadius: 12,
          fontWeight: 500,
        },
      },
    },
  },
});

// ==================== API SERVICE ====================

const API_BASE_URL = 'http://localhost:8000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: { 'Content-Type': 'application/json' },
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('access_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) localStorage.removeItem('access_token');
    return Promise.reject(error);
  }
);

// ==================== AUTH CONTEXT ====================

const AuthContext = React.createContext(null);

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    if (token) {
      api.get('/auth/profile')
        .then(response => setUser(response.data))
        .catch(() => localStorage.removeItem('access_token'))
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = async (username, password) => {
    const formData = new FormData();
    formData.append('username', username);
    formData.append('password', password);
    const response = await axios.post(`${API_BASE_URL}/auth/login`, formData);
    localStorage.setItem('access_token', response.data.access_token);
    const profileResponse = await api.get('/auth/profile');
    setUser(profileResponse.data);
    return response.data;
  };

  const signup = async (userData) => {
    const response = await api.post('/auth/signup', userData);
    return response.data;
  };

  const logout = () => {
    localStorage.removeItem('access_token');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, signup, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

// ==================== HOME PAGE ====================

const HomePage = () => {
  const navigate = useNavigate();

  const features = [
    { icon: <PsychologyIcon />, title: 'AI-Powered Analysis', description: 'Get intelligent insights and recommendations', color: '#ff69b4' },
    { icon: <SpeedIconNew />, title: 'Instant Results', description: 'Analyze your resume in seconds', color: '#ff6b6b' },
    { icon: <CalculateIcon />, title: 'ATS Score', description: 'Know your compatibility with ATS systems', color: '#ff922b' },
    { icon: <WorkIcon />, title: 'Job Matching', description: 'Find the perfect job matches', color: '#ff69b4' },
  ];

  const stats = [
    { value: '98%', label: 'Accuracy Rate', icon: <CheckCircleIcon /> },
    { value: '10K+', label: 'Resumes Analyzed', icon: <DescriptionIcon /> },
    { value: '500+', label: 'Companies', icon: <BusinessIcon /> },
    { value: '24/7', label: 'Support', icon: <SecurityIcon /> },
  ];

  return (
    <Box>
      {/* Hero Section */}
      <Box sx={{ background: theme.palette.primary.gradient, color: 'white', pt: 12, pb: 8, borderRadius: '0 0 40px 40px' }}>
        <Container maxWidth="lg">
          <Grid container spacing={6} alignItems="center">
            <Grid item xs={12} md={6}>
              <Grow in timeout={1000}>
                <Box>
                  <Chip
                    icon={<AutoAwesomeIcon />}
                    label="AI-Powered Resume Analysis"
                    sx={{ bgcolor: 'rgba(255,255,255,0.2)', color: 'white', mb: 3, '& .MuiChip-icon': { color: 'white' } }}
                  />
                  <Typography variant="h1" gutterBottom sx={{ fontSize: { xs: '2.5rem', md: '3.5rem' }, fontWeight: 800 }}>
                    Land Your Dream Job with AI
                  </Typography>
                  <Typography variant="h5" sx={{ mb: 4, opacity: 0.9, fontWeight: 400 }}>
                    Get past ATS systems with intelligent resume analysis and job matching powered by Google Gemini AI
                  </Typography>
                  <Stack direction="row" spacing={2}>
                    <Button
                      variant="contained"
                      size="large"
                      onClick={() => navigate('/signup')}
                      sx={{ bgcolor: 'white', color: '#ff69b4', '&:hover': { bgcolor: '#f0f0f0' }, px: 4 }}
                      startIcon={<RocketIcon />}
                    >
                      Get Started Free
                    </Button>
                    <Button
                      variant="outlined"
                      size="large"
                      onClick={() => navigate('/login')}
                      sx={{ borderColor: 'white', color: 'white', '&:hover': { borderColor: 'white', bgcolor: 'rgba(255,255,255,0.1)' } }}
                    >
                      Sign In
                    </Button>
                  </Stack>
                </Box>
              </Grow>
            </Grid>
            <Grid item xs={12} md={6}>
              <Zoom in timeout={1000}>
                <Box sx={{ textAlign: 'center' }}>
                  <img src="https://cdn-icons-png.flaticon.com/512/1055/1055687.png" alt="Resume" style={{ width: '80%', maxWidth: 300, filter: 'drop-shadow(0px 20px 40px rgba(0,0,0,0.2))' }} />
                </Box>
              </Zoom>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* Stats Section */}
      <Container maxWidth="lg" sx={{ mt: -4, mb: 6 }}>
        <Grid container spacing={3}>
          {stats.map((stat, index) => (
            <Grid item xs={6} md={3} key={index}>
              <Grow in timeout={1000 + index * 100}>
                <Card sx={{ textAlign: 'center', p: 3, bgcolor: 'white' }}>
                  <Box sx={{ color: theme.palette.primary.main, mb: 1 }}>{React.cloneElement(stat.icon, { sx: { fontSize: 40 } })}</Box>
                  <Typography variant="h3" fontWeight="bold">{stat.value}</Typography>
                  <Typography color="text.secondary">{stat.label}</Typography>
                </Card>
              </Grow>
            </Grid>
          ))}
        </Grid>
      </Container>

      {/* Features Section */}
      <Container maxWidth="lg" sx={{ py: 6 }}>
        <Typography variant="h2" align="center" gutterBottom sx={{ mb: 2 }}>Powerful Features</Typography>
        <Typography variant="h6" align="center" color="text.secondary" sx={{ mb: 6 }}>Everything you need to optimize your resume</Typography>
        <Grid container spacing={4}>
          {features.map((feature, index) => (
            <Grid item xs={12} sm={6} md={3} key={index}>
              <Fade in timeout={1000 + index * 200}>
                <Card sx={{ textAlign: 'center', p: 4, height: '100%', cursor: 'pointer', '&:hover': { transform: 'translateY(-8px)' } }}>
                  <Box sx={{ bgcolor: alpha(feature.color, 0.1), borderRadius: '50%', width: 80, height: 80, display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 20px' }}>
                    {React.cloneElement(feature.icon, { sx: { fontSize: 40, color: feature.color } })}
                  </Box>
                  <Typography variant="h6" gutterBottom>{feature.title}</Typography>
                  <Typography color="text.secondary">{feature.description}</Typography>
                </Card>
              </Fade>
            </Grid>
          ))}
        </Grid>
      </Container>

      {/* CTA Section */}
      <Box sx={{ bgcolor: '#fff0f5', py: 8, borderRadius: '40px', mx: 2, mb: 4 }}>
        <Container maxWidth="md" sx={{ textAlign: 'center' }}>
          <Typography variant="h3" gutterBottom>Ready to Transform Your Resume?</Typography>
          <Typography variant="h6" color="text.secondary" sx={{ mb: 4 }}>Join thousands of successful job seekers who improved their resumes with AI</Typography>
          <Button variant="contained" size="large" onClick={() => navigate('/signup')} sx={{ px: 6, py: 1.5 }} startIcon={<AutoAwesomeIcon />}>
            Start Free Trial
          </Button>
        </Container>
      </Box>
    </Box>
  );
};

// ==================== DASHBOARD PAGE ====================

const DashboardPage = () => {
  const [resumes, setResumes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ total: 0, avgScore: 0, bestScore: 0, totalAnalyses: 0 });
  const [recentActivity, setRecentActivity] = useState([]);
  const [viewMode, setViewMode] = useState('grid');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [resumesRes, historyRes] = await Promise.all([
        api.get('/resume/list'),
        api.get('/analysis/history')
      ]);

      setResumes(resumesRes.data);

      const atsAnalyses = historyRes.data.filter(a => a.analysis_type === 'ats_score');
      const avgScore = atsAnalyses.reduce((sum, a) => sum + (a.ats_score || 0), 0) / (atsAnalyses.length || 1);
      const bestScore = Math.max(...atsAnalyses.map(a => a.ats_score || 0), 0);

      setStats({
        total: resumesRes.data.length,
        avgScore: Math.round(avgScore),
        bestScore: Math.round(bestScore),
        totalAnalyses: historyRes.data.length
      });

      setRecentActivity(historyRes.data.slice(0, 5));
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const statCards = [
    { title: 'Total Resumes', value: stats.total, icon: <DescriptionIcon />, color: '#ff69b4', change: '+12%' },
    { title: 'Avg ATS Score', value: `${stats.avgScore}%`, icon: <TrendingUpIcon />, color: '#51cf66', change: '+5%' },
    { title: 'Best Score', value: `${stats.bestScore}%`, icon: <StarIcon />, color: '#ff922b', change: 'Top' },
    { title: 'Total Analyses', value: stats.totalAnalyses, icon: <AssessmentIcon />, color: '#ff6b6b', change: '+8%' },
  ];

  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh"><CircularProgress /></Box>;

  return (
    <Box>
      <Box sx={{ mb: 4 }}>
        <Typography variant="h4" gutterBottom fontWeight="bold">Welcome Back! 👋</Typography>
        <Typography variant="body1" color="text.secondary">Here's what's happening with your resumes today</Typography>
      </Box>

      <Grid container spacing={3} sx={{ mb: 4 }}>
        {statCards.map((stat, index) => (
          <Grid item xs={12} sm={6} md={3} key={index}>
            <Zoom in timeout={300 + index * 100}>
              <Card sx={{ p: 2 }}>
                <Box display="flex" justifyContent="space-between" alignItems="center">
                  <Box>
                    <Typography color="text.secondary" variant="body2">{stat.title}</Typography>
                    <Typography variant="h3" fontWeight="bold">{stat.value}</Typography>
                    <Chip label={stat.change} size="small" sx={{ mt: 1, bgcolor: alpha(stat.color, 0.1), color: stat.color }} />
                  </Box>
                  <Box sx={{ bgcolor: alpha(stat.color, 0.1), borderRadius: 2, p: 1 }}>
                    {React.cloneElement(stat.icon, { sx: { fontSize: 40, color: stat.color } })}
                  </Box>
                </Box>
              </Card>
            </Zoom>
          </Grid>
        ))}
      </Grid>

      <Box sx={{ mb: 4 }}>
        <Box display="flex" justifyContent="space-between" alignItems="center" sx={{ mb: 3 }}>
          <Typography variant="h5" fontWeight="bold">My Resumes</Typography>
          <Box display="flex" gap={1}>
            <ToggleButtonGroup value={viewMode} exclusive onChange={(e, v) => v && setViewMode(v)} size="small">
              <ToggleButton value="grid"><AppsIcon /></ToggleButton>
              <ToggleButton value="list"><FormatListBulletedIcon /></ToggleButton>
            </ToggleButtonGroup>
            <Button variant="contained" startIcon={<AddIcon />} component={Link} to="/upload">Upload New</Button>
          </Box>
        </Box>

        {resumes.length === 0 ? (
          <Card sx={{ textAlign: 'center', py: 8 }}>
            <InsertDriveFileIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} />
            <Typography variant="h6" gutterBottom>No Resumes Yet</Typography>
            <Typography color="text.secondary" sx={{ mb: 3 }}>Upload your first resume to get started</Typography>
            <Button variant="contained" component={Link} to="/upload" startIcon={<CloudUploadIcon />}>Upload Resume</Button>
          </Card>
        ) : viewMode === 'grid' ? (
          <Grid container spacing={3}>
            {resumes.map((resume, index) => (
              <Grid item xs={12} sm={6} md={4} key={resume.id}>
                <Grow in timeout={300 + index * 100}>
                  <Card sx={{ position: 'relative', overflow: 'visible' }}>
                    <Box sx={{ position: 'absolute', top: -12, right: 12 }}>
                      <Chip
                        icon={<CheckCircleIcon />}
                        label={`${resume.skills?.length || 0} skills`}
                        size="small"
                        sx={{ bgcolor: theme.palette.success.main, color: 'white' }}
                      />
                    </Box>
                    <CardContent>
                      <Box display="flex" alignItems="center" gap={2} sx={{ mb: 2 }}>
                        <Avatar sx={{ bgcolor: theme.palette.primary.main, width: 48, height: 48 }}>
                          {resume.name?.[0] || <DescriptionIcon />}
                        </Avatar>
                        <Box flex={1}>
                          <Typography variant="h6" noWrap>{resume.name || 'Unnamed Resume'}</Typography>
                          <Typography variant="body2" color="text.secondary" noWrap>{resume.filename}</Typography>
                        </Box>
                      </Box>
                      <Box sx={{ mb: 2 }}>
                        <Typography variant="body2" color="text.secondary" gutterBottom>Skills</Typography>
                        <Box display="flex" flexWrap="wrap" gap={0.5}>
                          {resume.skills?.slice(0, 4).map(skill => (
                            <Chip key={skill} label={skill} size="small" variant="outlined" />
                          ))}
                          {resume.skills?.length > 4 && <Chip label={`+${resume.skills.length - 4}`} size="small" />}
                        </Box>
                      </Box>
                    </CardContent>
                    <Divider />
                    <CardActions sx={{ p: 2, gap: 1 }}>
                      <Button size="small" startIcon={<VisibilityIcon />} component={Link} to={`/analyze?resume=${resume.id}`}>Analyze</Button>
                      <Button size="small" startIcon={<WorkIcon />} component={Link} to={`/match?resume=${resume.id}`}>Match Jobs</Button>
                      <IconButton size="small" color="error"><DeleteIcon /></IconButton>
                    </CardActions>
                  </Card>
                </Grow>
              </Grid>
            ))}
          </Grid>
        ) : (
          <TableContainer component={Paper}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Name</TableCell>
                  <TableCell>Filename</TableCell>
                  <TableCell>Skills</TableCell>
                  <TableCell>Uploaded</TableCell>
                  <TableCell>Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {resumes.map((resume) => (
                  <TableRow key={resume.id}>
                    <TableCell><Typography fontWeight="medium">{resume.name || 'Unnamed'}</Typography></TableCell>
                    <TableCell>{resume.filename}</TableCell>
                    <TableCell>
                      <Box display="flex" gap={0.5} flexWrap="wrap">
                        {resume.skills?.slice(0, 3).map(skill => <Chip key={skill} label={skill} size="small" />)}
                      </Box>
                    </TableCell>
                    <TableCell>{new Date(resume.uploaded_at).toLocaleDateString()}</TableCell>
                    <TableCell>
                      <IconButton size="small" component={Link} to={`/analyze?resume=${resume.id}`}><VisibilityIcon /></IconButton>
                      <IconButton size="small" color="error"><DeleteIcon /></IconButton>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </Box>

      {recentActivity.length > 0 && (
        <Card>
          <CardContent>
            <Typography variant="h6" fontWeight="bold" gutterBottom>Recent Activity</Typography>
            {recentActivity.map((activity, index) => (
              <Box key={index} sx={{ display: 'flex', alignItems: 'center', gap: 2, py: 1, borderBottom: index < recentActivity.length - 1 ? '1px solid' : 'none', borderColor: 'divider' }}>
                {activity.analysis_type === 'ats_score' ? <AssessmentIcon color="primary" /> : <WorkIcon color="secondary" />}
                <Box flex={1}>
                  <Typography variant="body2">{activity.resume_name}</Typography>
                  <Typography variant="caption" color="text.secondary">
                    {activity.analysis_type === 'ats_score' ? `ATS Score: ${Math.round(activity.ats_score)}%` : `Match: ${Math.round(activity.match_percentage)}%`}
                  </Typography>
                </Box>
                <Typography variant="caption" color="text.secondary">
                  {new Date(activity.created_at).toLocaleDateString()}
                </Typography>
              </Box>
            ))}
          </CardContent>
        </Card>
      )}
    </Box>
  );
};

// ==================== UPLOAD PAGE ====================

const UploadPage = () => {
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const navigate = useNavigate();

  const handleUpload = async () => {
    if (!file) {
      setMessage({ type: 'error', text: 'Please select a file' });
      return;
    }

    const formData = new FormData();
    formData.append('file', file);
    setUploading(true);
    try {
      const response = await api.post('/resume/upload', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
      setMessage({ type: 'success', text: 'Resume uploaded successfully! Redirecting...' });
      setTimeout(() => navigate('/dashboard'), 2000);
    } catch (error) {
      setMessage({ type: 'error', text: error.response?.data?.detail || 'Upload failed' });
    } finally {
      setUploading(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Upload Resume</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Upload your resume in PDF or DOCX format for AI-powered analysis</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={6}>
          <Card sx={{ p: 3 }}>
            <DropzoneArea
              acceptedFiles={['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document']}
              maxFileSize={10 * 1024 * 1024}
              filesLimit={1}
              onChange={(files) => setFile(files[0])}
              showAlerts={false}
              dropzoneText="Drag and drop your resume here or click to browse"
            />
            <Box sx={{ mt: 3, display: 'flex', justifyContent: 'center' }}>
              <Button variant="contained" onClick={handleUpload} disabled={!file || uploading} startIcon={<CloudUploadIcon />} size="large" sx={{ px: 6 }}>
                {uploading ? <CircularProgress size={24} /> : 'Upload Resume'}
              </Button>
            </Box>
            {message.text && (
              <Alert severity={message.type} sx={{ mt: 2 }}>
                {message.text}
              </Alert>
            )}
          </Card>
        </Grid>

        <Grid item xs={12} md={6}>
          <Card sx={{ p: 3, bgcolor: '#fff0f5' }}>
            <Typography variant="h6" gutterBottom>Supported Formats</Typography>
            <Box display="flex" gap={2} sx={{ mb: 3 }}>
              <Chip icon={<PictureAsPdfIcon />} label="PDF" color="primary" variant="outlined" />
              <Chip icon={<ArticleIcon />} label="DOCX" color="primary" variant="outlined" />
            </Box>
            <Typography variant="body2" color="text.secondary" gutterBottom>Requirements:</Typography>
            <List dense>
              <ListItem><CheckIcon sx={{ mr: 1, color: 'success.main', fontSize: 16 }} />Maximum file size: 10MB</ListItem>
              <ListItem><CheckIcon sx={{ mr: 1, color: 'success.main', fontSize: 16 }} />Text-based PDF or Word documents</ListItem>
              <ListItem><CheckIcon sx={{ mr: 1, color: 'success.main', fontSize: 16 }} />Clear section headings (Experience, Education, Skills)</ListItem>
            </List>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== ATS ANALYSIS PAGE ====================

const ATSAnalysisPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState(null);
  const [analysis, setAnalysis] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [tabValue, setTabValue] = useState(0);

  useEffect(() => {
    fetchResumes();
  }, []);

  const fetchResumes = async () => {
    try {
      const response = await api.get('/resume/list');
      setResumes(response.data);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedResume) return;
    setAnalyzing(true);
    try {
      const response = await api.post('/analyze/ats', { resume_id: selectedResume });
      setAnalysis(response.data);
    } catch (error) {
      console.error('Analysis error:', error);
    } finally {
      setAnalyzing(false);
    }
  };

  const getScoreColor = (score) => {
    if (score >= 80) return '#51cf66';
    if (score >= 60) return '#ff922b';
    return '#ff6b6b';
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">ATS Analysis</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Get AI-powered ATS score and detailed improvement suggestions</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={4}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>Select Resume</Typography>
              <List>
                {resumes.map((resume) => (
                  <ListItem
                    button
                    key={resume.id}
                    selected={selectedResume === resume.id}
                    onClick={() => setSelectedResume(resume.id)}
                    sx={{ borderRadius: 2, mb: 1, '&.Mui-selected': { bgcolor: alpha(theme.palette.primary.main, 0.1) } }}
                  >
                    <ListItemIcon><DescriptionIcon /></ListItemIcon>
                    <ListItemText primary={resume.name || resume.filename} secondary={new Date(resume.uploaded_at).toLocaleDateString()} />
                  </ListItem>
                ))}
              </List>
              {resumes.length === 0 && <Typography color="text.secondary" align="center">No resumes uploaded yet</Typography>}
              <Button variant="contained" fullWidth onClick={handleAnalyze} disabled={!selectedResume || analyzing} sx={{ mt: 2 }} startIcon={<AutoAwesomeIcon />}>
                {analyzing ? <CircularProgress size={24} /> : 'Analyze with AI'}
              </Button>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={8}>
          {analysis ? (
            <Fade in>
              <Card>
                <CardContent>
                  <Box textAlign="center" mb={4}>
                    <Box sx={{ position: 'relative', display: 'inline-block' }}>
                      <CircularProgress
                        variant="determinate"
                        value={analysis.ats_score}
                        size={120}
                        thickness={4}
                        sx={{ color: getScoreColor(analysis.ats_score) }}
                      />
                      <Box sx={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)' }}>
                        <Typography variant="h3" fontWeight="bold">{Math.round(analysis.ats_score)}%</Typography>
                      </Box>
                    </Box>
                    <Typography variant="body2" color="text.secondary" mt={1}>ATS Compatibility Score</Typography>
                  </Box>

                  <Tabs value={tabValue} onChange={(e, v) => setTabValue(v)} sx={{ mb: 3 }} variant="fullWidth">
                    <Tab icon={<ThumbUpIcon />} label="Strengths" />
                    <Tab icon={<ThumbDownIcon />} label="Weaknesses" />
                    <Tab icon={<SearchIcon />} label="Missing Keywords" />
                    <Tab icon={<AutoAwesomeIcon />} label="Suggestions" />
                  </Tabs>

                  <Box sx={{ mt: 2 }}>
                    {tabValue === 0 && (
                      <List>
                        {analysis.strengths?.map((strength, i) => (
                          <ListItem key={i}>
                            <CheckCircleIcon sx={{ color: 'success.main', mr: 2 }} />
                            <Typography>{strength}</Typography>
                          </ListItem>
                        ))}
                      </List>
                    )}
                    {tabValue === 1 && (
                      <List>
                        {analysis.weaknesses?.map((weakness, i) => (
                          <ListItem key={i}>
                            <ErrorIcon sx={{ color: 'error.main', mr: 2 }} />
                            <Typography>{weakness}</Typography>
                          </ListItem>
                        ))}
                      </List>
                    )}
                    {tabValue === 2 && (
                      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                        {analysis.missing_keywords?.map((keyword, i) => (
                          <Chip key={i} label={keyword} color="warning" icon={<WarningIcon />} />
                        ))}
                      </Box>
                    )}
                    {tabValue === 3 && (
                      <List>
                        {analysis.suggestions?.map((suggestion, i) => (
                          <ListItem key={i}>
                            <AutoAwesomeIcon sx={{ color: 'primary.main', mr: 2 }} />
                            <Typography>{suggestion}</Typography>
                          </ListItem>
                        ))}
                      </List>
                    )}
                  </Box>
                </CardContent>
              </Card>
            </Fade>
          ) : (
            <Card sx={{ textAlign: 'center', py: 8 }}>
              <PsychologyIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} />
              <Typography variant="h6" gutterBottom>No Analysis Yet</Typography>
              <Typography color="text.secondary">Select a resume and click "Analyze with AI" to get started</Typography>
            </Card>
          )}
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== JOB MATCHER PAGE ====================

const JobMatcherPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState(null);
  const [jobDescription, setJobDescription] = useState('');
  const [match, setMatch] = useState(null);
  const [matching, setMatching] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);

  useEffect(() => {
    fetchResumes();
  }, []);

  const fetchResumes = async () => {
    try {
      const response = await api.get('/resume/list');
      setResumes(response.data);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleMatch = async () => {
    if (!selectedResume || !jobDescription) return;
    setMatching(true);
    try {
      const response = await api.post('/analyze/match-job', { resume_id: selectedResume, job_description: jobDescription });
      setMatch(response.data);
      setOpenDialog(true);
    } catch (error) {
      console.error('Matching error:', error);
    } finally {
      setMatching(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Job Matcher</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Match your resume with job descriptions to find the perfect fit</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={4}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>Select Resume</Typography>
              <List>
                {resumes.map((resume) => (
                  <ListItem button key={resume.id} selected={selectedResume === resume.id} onClick={() => setSelectedResume(resume.id)} sx={{ borderRadius: 2, mb: 1 }}>
                    <ListItemIcon><DescriptionIcon /></ListItemIcon>
                    <ListItemText primary={resume.name || resume.filename} secondary={`${resume.skills?.length || 0} skills`} />
                  </ListItem>
                ))}
              </List>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={8}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>Job Description</Typography>
              <TextField
                fullWidth
                multiline
                rows={10}
                variant="outlined"
                placeholder="Paste the job description here..."
                value={jobDescription}
                onChange={(e) => setJobDescription(e.target.value)}
                sx={{ mb: 2 }}
              />
              <Button variant="contained" fullWidth onClick={handleMatch} disabled={!selectedResume || !jobDescription || matching} size="large" startIcon={<WorkIcon />}>
                {matching ? <CircularProgress size={24} /> : 'Match with Job'}
              </Button>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Dialog open={openDialog} onClose={() => setOpenDialog(false)} maxWidth="md" fullWidth>
        <DialogTitle>
          <Box display="flex" alignItems="center" justifyContent="space-between">
            <Typography variant="h5">Match Results</Typography>
            <Box textAlign="center">
              <Typography variant="h2" color="primary" fontWeight="bold">{Math.round(match?.match_percentage || 0)}%</Typography>
              <Typography variant="body2">Match Score</Typography>
            </Box>
          </Box>
        </DialogTitle>
        <DialogContent dividers>
          <Typography variant="h6" gutterBottom>Role Fit Summary</Typography>
          <Typography paragraph sx={{ bgcolor: '#fff0f5', p: 2, borderRadius: 2 }}>{match?.role_fit_summary}</Typography>

          <Typography variant="h6" gutterBottom>Matched Skills</Typography>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 3 }}>
            {match?.matched_skills?.map((skill, i) => <Chip key={i} label={skill} color="success" icon={<CheckCircleIcon />} />)}
          </Box>

          <Typography variant="h6" gutterBottom>Missing Skills</Typography>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
            {match?.missing_skills?.map((skill, i) => <Chip key={i} label={skill} color="error" icon={<ErrorIcon />} />)}
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenDialog(false)}>Close</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

// ==================== HISTORY PAGE ====================

const HistoryPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    fetchHistory();
  }, []);

  const fetchHistory = async () => {
    try {
      const response = await api.get('/analysis/history');
      setHistory(response.data);
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredHistory = history.filter(item => filter === 'all' || item.analysis_type === filter);

  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh"><CircularProgress /></Box>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Analysis History</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>View all your past resume analyses and job matches</Typography>

      <Box sx={{ mb: 3, display: 'flex', gap: 2 }}>
        <ToggleButtonGroup value={filter} exclusive onChange={(e, v) => v && setFilter(v)}>
          <ToggleButton value="all">All</ToggleButton>
          <ToggleButton value="ats_score">ATS Scores</ToggleButton>
          <ToggleButton value="job_match">Job Matches</ToggleButton>
        </ToggleButtonGroup>
      </Box>

      <Grid container spacing={2}>
        {filteredHistory.map((item, index) => (
          <Grid item xs={12} key={item.id}>
            <Fade in timeout={300 + index * 50}>
              <Card>
                <CardContent>
                  <Box display="flex" justifyContent="space-between" alignItems="center" flexWrap="wrap">
                    <Box>
                      <Typography variant="h6">{item.resume_name}</Typography>
                      <Typography variant="body2" color="text.secondary">
                        {new Date(item.created_at).toLocaleString()}
                      </Typography>
                      <Chip label={item.analysis_type === 'ats_score' ? 'ATS Score' : 'Job Match'} size="small" sx={{ mt: 1 }} />
                    </Box>
                    <Box textAlign="center">
                      <Typography variant="h3" color={item.analysis_type === 'ats_score' ? 'primary' : 'secondary'} fontWeight="bold">
                        {Math.round(item.analysis_type === 'ats_score' ? item.ats_score : item.match_percentage || 0)}%
                      </Typography>
                      <Typography variant="caption">{item.analysis_type === 'ats_score' ? 'ATS Score' : 'Match Rate'}</Typography>
                    </Box>
                  </Box>
                </CardContent>
              </Card>
            </Fade>
          </Grid>
        ))}
      </Grid>

      {history.length === 0 && (
        <Paper sx={{ textAlign: 'center', py: 8 }}>
          <HistoryIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} />
          <Typography variant="h6" gutterBottom>No History Yet</Typography>
          <Button variant="contained" component={Link} to="/upload" sx={{ mt: 2 }}>Upload Your First Resume</Button>
        </Paper>
      )}
    </Box>
  );
};

// ==================== LOGIN PAGE ====================

const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await login(username, password);
      navigate('/dashboard');
    } catch (error) {
      setError('Invalid username or password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: theme.palette.primary.gradient }}>
      <Container maxWidth="sm">
        <Card sx={{ p: 4 }}>
          <Box textAlign="center" mb={4}>
            <Avatar sx={{ bgcolor: theme.palette.primary.main, width: 64, height: 64, margin: '0 auto', mb: 2 }}><AnalyticsIcon sx={{ fontSize: 32 }} /></Avatar>
            <Typography variant="h4" fontWeight="bold">Welcome Back</Typography>
            <Typography color="text.secondary">Sign in to your account</Typography>
          </Box>
          <form onSubmit={handleSubmit}>
            <TextField fullWidth label="Username" value={username} onChange={(e) => setUsername(e.target.value)} margin="normal" required />
            <TextField fullWidth label="Password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} margin="normal" required />
            {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}
            <Button type="submit" fullWidth variant="contained" size="large" disabled={loading} sx={{ mt: 3 }}>
              {loading ? <CircularProgress size={24} /> : 'Sign In'}
            </Button>
          </form>
          <Box textAlign="center" mt={2}>
            <Typography variant="body2">Don't have an account? <Link to="/signup" style={{ color: theme.palette.primary.main }}>Sign Up</Link></Typography>
          </Box>
        </Card>
      </Container>
    </Box>
  );
};

// ==================== SIGNUP PAGE ====================

const SignupPage = () => {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const { signup } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await signup(formData);
      setSuccess(true);
      setTimeout(() => navigate('/login'), 2000);
    } catch (error) {
      setError(error.response?.data?.detail || 'Signup failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: theme.palette.primary.gradient }}>
      <Container maxWidth="sm">
        <Card sx={{ p: 4 }}>
          <Box textAlign="center" mb={4}>
            <Avatar sx={{ bgcolor: theme.palette.primary.main, width: 64, height: 64, margin: '0 auto', mb: 2 }}><AppRegistrationIcon sx={{ fontSize: 32 }} /></Avatar>
            <Typography variant="h4" fontWeight="bold">Create Account</Typography>
            <Typography color="text.secondary">Get started with AI resume analysis</Typography>
          </Box>
          <form onSubmit={handleSubmit}>
            <TextField fullWidth label="Username" value={formData.username} onChange={(e) => setFormData({ ...formData, username: e.target.value })} margin="normal" required />
            <TextField fullWidth label="Email" type="email" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} margin="normal" required />
            <TextField fullWidth label="Password" type="password" value={formData.password} onChange={(e) => setFormData({ ...formData, password: e.target.value })} margin="normal" required />
            {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}
            {success && <Alert severity="success" sx={{ mt: 2 }}>Account created! Redirecting to login...</Alert>}
            <Button type="submit" fullWidth variant="contained" size="large" disabled={loading} sx={{ mt: 3 }}>
              {loading ? <CircularProgress size={24} /> : 'Sign Up'}
            </Button>
          </form>
          <Box textAlign="center" mt={2}>
            <Typography variant="body2">Already have an account? <Link to="/login" style={{ color: theme.palette.primary.main }}>Sign In</Link></Typography>
          </Box>
        </Card>
      </Container>
    </Box>
  );
};

// ==================== LAYOUT COMPONENT ====================

const Layout = ({ children }) => {
  const [drawerOpen, setDrawerOpen] = useState(false);
  const { user, logout } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const menuItems = [
    { text: 'Dashboard', icon: <DashboardIcon />, path: '/dashboard' },
    { text: 'Upload Resume', icon: <UploadIcon />, path: '/upload' },
    { text: 'ATS Analysis', icon: <AssessmentIcon />, path: '/analyze' },
    { text: 'Job Matcher', icon: <WorkIcon />, path: '/match' },
    { text: 'History', icon: <HistoryIcon />, path: '/history' },
  ];

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ zIndex: 1201, background: theme.palette.primary.gradient }}>
        <Toolbar>
          <IconButton color="inherit" edge="start" onClick={() => setDrawerOpen(true)} sx={{ mr: 2, display: { sm: 'none' } }}><MenuIcon /></IconButton>
          <AnalyticsIcon sx={{ mr: 2 }} />
          <Typography variant="h6" sx={{ flexGrow: 1, cursor: 'pointer' }} onClick={() => navigate('/')}>Resume Analyzer</Typography>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
            <Chip avatar={<Avatar sx={{ bgcolor: 'white', color: '#ff69b4' }}>{user?.username?.[0]}</Avatar>} label={user?.username} variant="outlined" sx={{ color: 'white', borderColor: 'white' }} />
            <IconButton color="inherit" onClick={logout}><LogoutIcon /></IconButton>
          </Box>
        </Toolbar>
      </AppBar>

      <Drawer variant="permanent" sx={{ display: { xs: 'none', sm: 'block' }, '& .MuiDrawer-paper': { width: 280, boxSizing: 'border-box', mt: 8 } }} open>
        <List>
          {menuItems.map((item) => (
            <ListItem button key={item.text} onClick={() => navigate(item.path)} sx={{ mx: 1, borderRadius: 2, mb: 0.5 }}>
              <ListItemIcon sx={{ color: theme.palette.primary.main }}>{item.icon}</ListItemIcon>
              <ListItemText primary={item.text} />
            </ListItem>
          ))}
        </List>
      </Drawer>

      <Drawer variant="temporary" open={drawerOpen} onClose={() => setDrawerOpen(false)} sx={{ display: { xs: 'block', sm: 'none' } }}>
        <List>
          {menuItems.map((item) => (
            <ListItem button key={item.text} onClick={() => { navigate(item.path); setDrawerOpen(false); }}>
              <ListItemIcon sx={{ color: theme.palette.primary.main }}>{item.icon}</ListItemIcon>
              <ListItemText primary={item.text} />
            </ListItem>
          ))}
        </List>
      </Drawer>

      <Box component="main" sx={{ flexGrow: 1, p: 3, mt: 8, backgroundColor: '#fff5f8', minHeight: '100vh' }}>
        {children}
      </Box>
    </Box>
  );
};

// ==================== MAIN APP ====================

const App = () => {
  const { user, loading } = React.useContext(AuthContext);
  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="100vh"><CircularProgress /></Box>;

  return (
    <Router>
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <LoginPage />} />
        <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <SignupPage />} />
        <Route path="/dashboard" element={user ? <Layout><DashboardPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/upload" element={user ? <Layout><UploadPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/analyze" element={user ? <Layout><ATSAnalysisPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/match" element={user ? <Layout><JobMatcherPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/history" element={user ? <Layout><HistoryPage /></Layout> : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
};

// ==================== APP WRAPPER ====================

const AppWrapper = () => {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AuthProvider>
        <App />
      </AuthProvider>
    </ThemeProvider>
  );
};

export default AppWrapper;
